// src/components/HomePage.js
function HomePage({ notes, openModal }) {
  return (
    <div className="p-4 h-screen bg-gray-100">
      <h1 className="text-3xl font-bold mb-6 text-slate-800">Your Notes</h1>
      
      {/* 1. The Search Bar and Filter (Optional but recommended) */}
      <input 
        type="text" 
        placeholder="Search notes..."
        className="w-full p-2 mb-4 border rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
      />
      
      {/* 2. Note List */}
      <div className="space-y-4">
        {notes.map(note => (
          <Note key={note.id} note={note} onClick={() => openModal(note)} />
        ))}
      </div>

      {/* 3. Floating Action Button (FAB) */}
      <button 
        onClick={() => openModal(null)} // null means 'create new note'
        className="fixed bottom-8 right-8 bg-blue-600 text-white p-4 rounded-full shadow-lg hover:bg-blue-700 transition-colors"
        title="Add New Note"
      >
        <span className="text-2xl">+</span>
      </button>
    </div>
  );
}
